import{_ as a,o as t,c as s,a2 as p}from"./chunks/framework.wSsqAhVZ.js";const b=JSON.parse('{"title":"二叉搜索树小结：中序有序与查找导航","description":"","frontmatter":{},"headers":[],"relativePath":"go-code-thoughts/7_tree/21_小总结.md","filePath":"go-code-thoughts/7_tree/21_小总结.md","lastUpdated":1784004070000}'),n={name:"go-code-thoughts/7_tree/21_小总结.md"};function i(r,e,o,l,d,c){return t(),s("div",null,[...e[0]||(e[0]=[p('<h1 id="二叉搜索树小结-中序有序与查找导航" tabindex="-1">二叉搜索树小结：中序有序与查找导航 <a class="header-anchor" href="#二叉搜索树小结-中序有序与查找导航" aria-label="Permalink to &quot;二叉搜索树小结：中序有序与查找导航&quot;">​</a></h1><p>二叉搜索树有两个非常重要的性质。</p><p>第一，BST 的中序遍历结果是有序数组。</p><p>第二，BST 具有查找导航能力： 每一步都能根据当前节点值决定向左还是向右。</p><h2 id="中序遍历有序" tabindex="-1">中序遍历有序 <a class="header-anchor" href="#中序遍历有序" aria-label="Permalink to &quot;中序遍历有序&quot;">​</a></h2><p>很多 BST 题目可以通过中序遍历转化成有序数组问题。</p><h3 id="_98-验证二叉搜索树" tabindex="-1">98 验证二叉搜索树 <a class="header-anchor" href="#_98-验证二叉搜索树" aria-label="Permalink to &quot;98 验证二叉搜索树&quot;">​</a></h3><p><a href="https://leetcode.cn/problems/validate-binary-search-tree/" target="_blank" rel="noreferrer">题目链接</a></p><p>树的问题：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>判断一棵树是不是有效 BST</span></span></code></pre></div><p>数组视角：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>判断中序遍历结果是否严格递增</span></span></code></pre></div><h3 id="_530-二叉搜索树的最小绝对差" tabindex="-1">530 二叉搜索树的最小绝对差 <a class="header-anchor" href="#_530-二叉搜索树的最小绝对差" aria-label="Permalink to &quot;530 二叉搜索树的最小绝对差&quot;">​</a></h3><p><a href="https://leetcode.cn/problems/minimum-absolute-difference-in-bst/" target="_blank" rel="noreferrer">题目链接</a></p><p>树的问题：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>找树中任意两个节点值之间的最小差值</span></span></code></pre></div><p>数组视角：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在有序数组中找相邻元素的最小差值</span></span></code></pre></div><h3 id="_501-二叉搜索树中的众数" tabindex="-1">501 二叉搜索树中的众数 <a class="header-anchor" href="#_501-二叉搜索树中的众数" aria-label="Permalink to &quot;501 二叉搜索树中的众数&quot;">​</a></h3><p><a href="https://leetcode.cn/problems/find-mode-in-binary-search-tree/" target="_blank" rel="noreferrer">题目链接</a></p><p>树的问题：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>找树中出现频率最高的元素</span></span></code></pre></div><p>数组视角：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在有序数组中统计连续相同元素的最长段</span></span></code></pre></div><p>因为中序遍历有序，相同元素会连续出现。 这让遍历过程中的连续计数变得可行。</p><h2 id="查找导航能力" tabindex="-1">查找导航能力 <a class="header-anchor" href="#查找导航能力" aria-label="Permalink to &quot;查找导航能力&quot;">​</a></h2><p>BST 还有另一个重要能力：根据当前节点值决定搜索方向。</p><p>例如：</p><p><a href="https://leetcode.cn/problems/search-in-a-binary-search-tree/" target="_blank" rel="noreferrer">700 二叉搜索树中的搜索</a></p><p>如果目标值小于当前节点值，只需要去左子树。</p><p>如果目标值大于当前节点值，只需要去右子树。</p><p>这类问题利用的是 BST 的二分式导航能力。</p><p>未来的插入、删除等操作，也会大量依赖这个性质。</p><h2 id="本篇总结" tabindex="-1">本篇总结 <a class="header-anchor" href="#本篇总结" aria-label="Permalink to &quot;本篇总结&quot;">​</a></h2><p>BST 题目可以先判断它主要利用哪种性质。</p><p>如果题目和节点值顺序、大小关系、相邻关系有关， 优先考虑中序遍历。</p><p>如果题目和查找、插入、删除某个目标值有关， 优先考虑 BST 的导航性质。</p><p>这两个性质是理解 BST 题目的核心。</p>',38)])])}const u=a(n,[["render",i]]);export{b as __pageData,u as default};
